What does this program print?

```cpp
#include <iostream>
#include <vector>

int main()
{
    std::vector<int> v;
    v.push_back(1);
    v.push_back(2);
    v.push_back(3);
    v.pop_back();
    std::cout << v.back() << ' ' << v.size() << '\n';
}
```

